     9→
    10→import { gmail_v1 } from 'googleapis';
    11→import { GmailClient } from './gmail-client';
    12→
    13→/**
    14→ * Email address representation
    15→ */
    16→export interface EmailAddress {
    17→  /**
    18→   * Email address
    19→   */
    20→  email: string;
    21→
    22→  /**
    23→   * Display name (if available)
    24→   */
    25→  name?: string;
    26→
    27→  /**
