/**
 * Gmail API Client with OAuth2 Authentication
 *
 * Provides secure Gmail API access with authentication, token management,
 * rate limiting, and error handling capabilities.
 *
 * @packageDocumentation
 */

import { gmail_v1, google } from 'googleapis';
import { OAuth2Client } from 'google-auth-library';

/**
 * OAuth2 credentials for Gmail API authentication
 */
export interface OAuth2Credentials {
  /**
   * OAuth2 client ID from Google Cloud Console
   */
  clientId: string;

  /**
   * OAuth2 client secret from Google Cloud Console
   */
  clientSecret: string;

  /**
   * OAuth2 redirect URI for authorization callback
   */
  redirectUri: string;
}

/**
 * OAuth2 token set returned from Google
 */
export interface OAuth2Tokens {
  /**
   * Access token for API requests
   */
  access_token: string | null | undefined;

  /**
   * Refresh token for obtaining new access tokens
   */
  refresh_token?: string | null;

  /**
   * Token expiration timestamp (milliseconds since epoch)
   */
  expiry_date?: number | null;

  /**
   * Token type (usually "Bearer")
   */
  token_type?: string;

  /**
   * Granted scopes
   */
  scope?: string;
}

/**
 * Gmail authentication status information
 */
export interface AuthStatus {
  /**
   * Whether OAuth2 credentials are configured
   */
  authenticated: boolean;

  /**
   * Whether the access token is valid and not expired
   */
  tokenValid: boolean;

  /**
   * Authenticated user's email address
   */
  userEmail?: string;

  /**
   * Token expiration timestamp
   */
  tokenExpiresAt?: Date;

  /**
   * Granted OAuth2 scopes
   */
  scopes?: string[];

  /**
   * Timestamp when status was checked
   */
  lastChecked: Date;
}

/**
 * Options for Gmail API requests
 */
export interface GmailRequestOptions {
  /**
   * Whether to retry on rate limit errors (429)
   * @default false
   */
  retryOnRateLimit?: boolean;

  /**
   * Maximum number of retry attempts
   * @default 3
   */
  maxRetries?: number;

  /**
   * Base delay in milliseconds between retries
   * @default 1000
   */
  retryDelayMs?: number;
}

/**
 * Gmail API client with OAuth2 authentication and rate limiting support
 *
 * Handles OAuth2 authentication flows, token management, and provides
 * robust error handling with retry logic for rate limit errors.
 *
 * @example
 * ```typescript
 * // Initialize with environment variables
 * const client = new GmailClient();
 *
 * // Or with explicit credentials
 * const client = new GmailClient({
 *   clientId: 'your-client-id',
 *   clientSecret: 'your-client-secret',
 *   redirectUri: 'http://localhost:3000/oauth2callback'
 * });
 *
 * // Set tokens after OAuth2 flow
 * await client.setTokens(tokens);
 *
 * // Fetch user profile
 * const profile = await client.getUserProfile();
 * ```
