/**
 * Unit tests for Gmail email fetcher with pagination
 *
 * TDD implementation: These tests are written FIRST before the implementation
 * to define the expected behavior of the email fetcher.
 *
 * @packageDocumentation
 */

/* eslint-disable @typescript-eslint/no-explicit-any */

import { EmailFetcher } from '../../src/gmail/email-fetcher';
import { GmailClient } from '../../src/gmail/gmail-client';
import { gmail_v1 } from 'googleapis';

// Mock the GmailClient
jest.mock('../../src/gmail/gmail-client');

describe('EmailFetcher', () => {
  let emailFetcher: EmailFetcher;
  let mockGmailClient: jest.Mocked<GmailClient>;
  let mockGmailApi: jest.Mocked<gmail_v1.Gmail>;

  beforeEach(() => {
    jest.clearAllMocks();

    // Create mock Gmail API instance
    mockGmailApi = {
      users: {
        messages: {
          list: jest.fn(),
          get: jest.fn(),
        },
      },
    } as any;

    // Create mock Gmail client
    mockGmailClient = {
      getGmailApi: jest.fn(() => mockGmailApi),
      getAuthStatus: jest.fn(),
    } as any;

    // Create email fetcher instance
    emailFetcher = new EmailFetcher(mockGmailClient);
  });

  describe('constructor', () => {
    it('should create EmailFetcher with GmailClient', () => {
      expect(emailFetcher).toBeInstanceOf(EmailFetcher);
      expect(mockGmailClient.getGmailApi).toHaveBeenCalled();
    });
  });

  describe('fetchEmails - basic fetching', () => {
    it('should fetch emails with default options', async () => {
      const mockMessages = [
        { id: 'msg1', threadId: 'thread1' },
        { id: 'msg2', threadId: 'thread2' },
      ];

      const mockMessageDetails = [
        {
          id: 'msg1',
          threadId: 'thread1',
          labelIds: ['INBOX'],
          payload: {
            headers: [
              { name: 'From', value: 'sender1@example.com' },
              { name: 'To', value: 'user@example.com' },
              { name: 'Subject', value: 'Test Email 1' },
              { name: 'Date', value: 'Mon, 01 Jan 2024 10:00:00 +0000' },
            ],
          },
          snippet: 'Test snippet 1',
        },
        {
          id: 'msg2',
          threadId: 'thread2',
          labelIds: ['INBOX'],
          payload: {
            headers: [
              { name: 'From', value: 'sender2@example.com' },
              { name: 'To', value: 'user@example.com' },
              { name: 'Subject', value: 'Test Email 2' },
              { name: 'Date', value: 'Mon, 01 Jan 2024 11:00:00 +0000' },
            ],
          },
          snippet: 'Test snippet 2',
        },
      ];

      // Mock list response
      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: mockMessages,
          resultSizeEstimate: 2,
        },
      });

      // Mock get responses for each message
      (mockGmailApi.users.messages.get as jest.Mock)
        .mockResolvedValueOnce({ data: mockMessageDetails[0] })
        .mockResolvedValueOnce({ data: mockMessageDetails[1] });

      const result = await emailFetcher.fetchEmails();

      expect(result.emails).toHaveLength(2);
      expect(result.totalFetched).toBe(2);
      expect(result.hasMore).toBe(false);
      expect(mockGmailApi.users.messages.list).toHaveBeenCalledWith({
        userId: 'me',
        maxResults: 100,
      });
    });

    it('should respect maxResults option', async () => {
      const mockMessages = [{ id: 'msg1', threadId: 'thread1' }];

      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: mockMessages,
          resultSizeEstimate: 1,
        },
      });

      (mockGmailApi.users.messages.get as jest.Mock).mockResolvedValue({
        data: {
          id: 'msg1',
          threadId: 'thread1',
          labelIds: ['INBOX'],
          payload: { headers: [] },
        },
      });

      await emailFetcher.fetchEmails({ maxResults: 10 });

      expect(mockGmailApi.users.messages.list).toHaveBeenCalledWith({
        userId: 'me',
        maxResults: 10,
      });
    });

    it('should apply query filter when provided', async () => {
      const mockMessages = [{ id: 'msg1', threadId: 'thread1' }];

      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: mockMessages,
          resultSizeEstimate: 1,
        },
      });

      (mockGmailApi.users.messages.get as jest.Mock).mockResolvedValue({
        data: {
          id: 'msg1',
          threadId: 'thread1',
          labelIds: ['INBOX'],
          payload: { headers: [] },
        },
      });

      await emailFetcher.fetchEmails({ query: 'is:unread' });

      expect(mockGmailApi.users.messages.list).toHaveBeenCalledWith({
        userId: 'me',
        maxResults: 100,
        q: 'is:unread',
      });
    });

    it('should filter by label IDs when provided', async () => {
      const mockMessages = [{ id: 'msg1', threadId: 'thread1' }];

      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: mockMessages,
          resultSizeEstimate: 1,
        },
      });

      (mockGmailApi.users.messages.get as jest.Mock).mockResolvedValue({
        data: {
          id: 'msg1',
          threadId: 'thread1',
          labelIds: ['INBOX'],
          payload: { headers: [] },
        },
      });

      await emailFetcher.fetchEmails({ labelIds: ['INBOX', 'UNREAD'] });

      expect(mockGmailApi.users.messages.list).toHaveBeenCalledWith({
        userId: 'me',
        maxResults: 100,
        labelIds: ['INBOX', 'UNREAD'],
      });
    });

    it('should return empty array when no emails found', async () => {
      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: undefined,
          resultSizeEstimate: 0,
        },
      });

      const result = await emailFetcher.fetchEmails();

      expect(result.emails).toHaveLength(0);
      expect(result.totalFetched).toBe(0);
      expect(result.hasMore).toBe(false);
    });
  });

  describe('fetchEmails - pagination', () => {
    it('should handle pagination with nextPageToken', async () => {
      const mockMessages = [{ id: 'msg1', threadId: 'thread1' }];

      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: mockMessages,
          nextPageToken: 'token123',
          resultSizeEstimate: 100,
        },
      });

      (mockGmailApi.users.messages.get as jest.Mock).mockResolvedValue({
        data: {
          id: 'msg1',
          threadId: 'thread1',
          labelIds: ['INBOX'],
          payload: { headers: [] },
        },
      });

      const result = await emailFetcher.fetchEmails({ maxResults: 10 });

      expect(result.hasMore).toBe(true);
      expect(result.nextPageToken).toBe('token123');
    });

    it('should use pageToken to fetch next page', async () => {
      const mockMessages = [{ id: 'msg2', threadId: 'thread2' }];

      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: mockMessages,
          resultSizeEstimate: 1,
        },
      });

      (mockGmailApi.users.messages.get as jest.Mock).mockResolvedValue({
        data: {
          id: 'msg2',
          threadId: 'thread2',
          labelIds: ['INBOX'],
          payload: { headers: [] },
        },
      });

      await emailFetcher.fetchEmails({ pageToken: 'token123' });

      expect(mockGmailApi.users.messages.list).toHaveBeenCalledWith({
        userId: 'me',
        maxResults: 100,
        pageToken: 'token123',
      });
    });

    it('should fetch all pages when fetchAll is true', async () => {
      // First page
      const mockMessagesPage1 = [
        { id: 'msg1', threadId: 'thread1' },
        { id: 'msg2', threadId: 'thread2' },
      ];

      // Second page
      const mockMessagesPage2 = [{ id: 'msg3', threadId: 'thread3' }];

      (mockGmailApi.users.messages.list as jest.Mock)
        .mockResolvedValueOnce({
          data: {
            messages: mockMessagesPage1,
            nextPageToken: 'token123',
            resultSizeEstimate: 3,
          },
        })
        .mockResolvedValueOnce({
          data: {
            messages: mockMessagesPage2,
            resultSizeEstimate: 3,
          },
        });

      (mockGmailApi.users.messages.get as jest.Mock)
        .mockResolvedValueOnce({
          data: { id: 'msg1', threadId: 'thread1', labelIds: ['INBOX'], payload: { headers: [] } },
        })
        .mockResolvedValueOnce({
          data: { id: 'msg2', threadId: 'thread2', labelIds: ['INBOX'], payload: { headers: [] } },
        })
        .mockResolvedValueOnce({
          data: { id: 'msg3', threadId: 'thread3', labelIds: ['INBOX'], payload: { headers: [] } },
        });

      const result = await emailFetcher.fetchEmails({ maxResults: 2, fetchAll: true });

      expect(result.emails).toHaveLength(3);
      expect(result.totalFetched).toBe(3);
      expect(result.hasMore).toBe(false);
      expect(mockGmailApi.users.messages.list).toHaveBeenCalledTimes(2);
    });
  });

  describe('fetchEmails - batch processing', () => {
    it('should fetch message details in batches', async () => {
      const mockMessages = Array.from({ length: 5 }, (_, i) => ({
        id: `msg${i + 1}`,
        threadId: `thread${i + 1}`,
      }));

      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: mockMessages,
          resultSizeEstimate: 5,
        },
      });

      // Mock get responses
      mockMessages.forEach((msg) => {
        (mockGmailApi.users.messages.get as jest.Mock).mockResolvedValueOnce({
          data: {
            id: msg.id,
            threadId: msg.threadId,
            labelIds: ['INBOX'],
            payload: { headers: [] },
          },
        });
      });

      const result = await emailFetcher.fetchEmails({ batchSize: 2 });

      expect(result.emails).toHaveLength(5);
      expect(mockGmailApi.users.messages.get).toHaveBeenCalledTimes(5);
    });

    it('should handle batch processing errors gracefully', async () => {
      const mockMessages = [
        { id: 'msg1', threadId: 'thread1' },
        { id: 'msg2', threadId: 'thread2' },
        { id: 'msg3', threadId: 'thread3' },
      ];

      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: mockMessages,
          resultSizeEstimate: 3,
        },
      });

      // First message succeeds, second fails, third succeeds
      (mockGmailApi.users.messages.get as jest.Mock)
        .mockResolvedValueOnce({
          data: { id: 'msg1', threadId: 'thread1', labelIds: ['INBOX'], payload: { headers: [] } },
        })
        .mockRejectedValueOnce(new Error('API error'))
        .mockResolvedValueOnce({
          data: { id: 'msg3', threadId: 'thread3', labelIds: ['INBOX'], payload: { headers: [] } },
        });

      const result = await emailFetcher.fetchEmails();

      expect(result.emails).toHaveLength(2); // Only successful fetches
      expect(result.errors).toHaveLength(1);
      expect(result.errors[0].messageId).toBe('msg2');
    });
  });

  describe('fetchEmails - error handling', () => {
    it('should throw error when list API call fails', async () => {
      (mockGmailApi.users.messages.list as jest.Mock).mockRejectedValue(new Error('API error'));

      await expect(emailFetcher.fetchEmails()).rejects.toThrow('API error');
    });

    it('should continue fetching on individual message errors when continueOnError is true', async () => {
      const mockMessages = [
        { id: 'msg1', threadId: 'thread1' },
        { id: 'msg2', threadId: 'thread2' },
      ];

      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: mockMessages,
          resultSizeEstimate: 2,
        },
      });

      (mockGmailApi.users.messages.get as jest.Mock)
        .mockRejectedValueOnce(new Error('Message 1 error'))
        .mockResolvedValueOnce({
          data: { id: 'msg2', threadId: 'thread2', labelIds: ['INBOX'], payload: { headers: [] } },
        });

      const result = await emailFetcher.fetchEmails({ continueOnError: true });

      expect(result.emails).toHaveLength(1);
      expect(result.emails[0].id).toBe('msg2');
      expect(result.errors).toHaveLength(1);
      expect(result.errors[0].messageId).toBe('msg1');
    });

    it('should stop fetching on first error when continueOnError is false', async () => {
      const mockMessages = [
        { id: 'msg1', threadId: 'thread1' },
        { id: 'msg2', threadId: 'thread2' },
      ];

      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: mockMessages,
          resultSizeEstimate: 2,
        },
      });

      (mockGmailApi.users.messages.get as jest.Mock).mockRejectedValue(new Error('Message error'));

      await expect(emailFetcher.fetchEmails({ continueOnError: false })).rejects.toThrow('Message error');
    });
  });

  describe('fetchEmails - Gmail API response parsing', () => {
    it('should parse full email format correctly', async () => {
      const mockMessage = {
        id: 'msg1',
        threadId: 'thread1',
        labelIds: ['INBOX', 'UNREAD'],
        snippet: 'This is a test email',
        historyId: '12345',
        internalDate: '1704110400000',
        payload: {
          partId: '',
          mimeType: 'multipart/alternative',
          headers: [
            { name: 'From', value: 'Sender Name <sender@example.com>' },
            { name: 'To', value: 'Recipient <recipient@example.com>' },
            { name: 'Subject', value: 'Test Subject' },
            { name: 'Date', value: 'Mon, 01 Jan 2024 10:00:00 +0000' },
            { name: 'Message-ID', value: '<message-id@example.com>' },
          ],
          body: {
            size: 0,
          },
          parts: [
            {
              partId: '0',
              mimeType: 'text/plain',
              body: {
                size: 100,
                data: 'VGVzdCBwbGFpbiB0ZXh0', // Base64: "Test plain text"
              },
            },
            {
              partId: '1',
              mimeType: 'text/html',
              body: {
                size: 150,
                data: 'PHA+VGVzdCBIVE1MPC9wPg==', // Base64: "<p>Test HTML</p>"
              },
            },
          ],
        },
        sizeEstimate: 5000,
      };

      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: [{ id: 'msg1', threadId: 'thread1' }],
          resultSizeEstimate: 1,
        },
      });

      (mockGmailApi.users.messages.get as jest.Mock).mockResolvedValue({
        data: mockMessage,
      });

      const result = await emailFetcher.fetchEmails({ format: 'full' });

      expect(result.emails).toHaveLength(1);
      const email = result.emails[0];

      expect(email.id).toBe('msg1');
      expect(email.threadId).toBe('thread1');
      expect(email.gmailLabels).toEqual(['INBOX', 'UNREAD']);
      expect(email.snippet).toBe('This is a test email');
      expect(email.subject).toBe('Test Subject');
      expect(email.from).toBeDefined();
      expect(email.from?.email).toBe('sender@example.com');
      expect(email.from?.name).toBe('Sender Name');
      expect(email.to).toBeDefined();
      expect(email.to?.[0].email).toBe('recipient@example.com');
    });

    it('should handle minimal format correctly', async () => {
      const mockMessage = {
        id: 'msg1',
        threadId: 'thread1',
        labelIds: ['INBOX'],
      };

      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: [{ id: 'msg1', threadId: 'thread1' }],
          resultSizeEstimate: 1,
        },
      });

      (mockGmailApi.users.messages.get as jest.Mock).mockResolvedValue({
        data: mockMessage,
      });

      const result = await emailFetcher.fetchEmails({ format: 'minimal' });

      expect(result.emails).toHaveLength(1);
      expect(result.emails[0].id).toBe('msg1');
      expect(mockGmailApi.users.messages.get).toHaveBeenCalledWith({
        userId: 'me',
        id: 'msg1',
        format: 'minimal',
      });
    });
  });

  describe('fetchEmailById', () => {
    it('should fetch single email by ID', async () => {
      const mockMessage = {
        id: 'msg1',
        threadId: 'thread1',
        labelIds: ['INBOX'],
        payload: {
          headers: [
            { name: 'From', value: 'sender@example.com' },
            { name: 'To', value: 'recipient@example.com' },
            { name: 'Subject', value: 'Test' },
            { name: 'Date', value: 'Mon, 01 Jan 2024 10:00:00 +0000' },
          ],
        },
      };

      (mockGmailApi.users.messages.get as jest.Mock).mockResolvedValue({
        data: mockMessage,
      });

      const result = await emailFetcher.fetchEmailById('msg1');

      expect(result.id).toBe('msg1');
      expect(mockGmailApi.users.messages.get).toHaveBeenCalledWith({
        userId: 'me',
        id: 'msg1',
        format: 'full',
