        id: 'msg1',
        threadId: 'thread1',
        labelIds: ['INBOX'],
        payload: {
          headers: [
            { name: 'From', value: 'sender@example.com' },
            { name: 'To', value: '"Smith, John" <john@example.com>, "Doe, Jane" <jane@example.com>' },
            { name: 'Subject', value: 'Test' },
            { name: 'Date', value: 'Mon, 01 Jan 2024 10:00:00 +0000' },
          ],
        },
      };

      (mockGmailApi.users.messages.list as jest.Mock).mockResolvedValue({
        data: {
          messages: [{ id: 'msg1', threadId: 'thread1' }],
          resultSizeEstimate: 1,
        },
      });

      (mockGmailApi.users.messages.get as jest.Mock).mockResolvedValue({
        data: mockMessage,
      });

      const result = await emailFetcher.fetchEmails();

      expect(result.emails).toHaveLength(1);
      expect(result.emails[0].to).toHaveLength(2);
      expect(result.emails[0].to?.[0].email).toBe('john@example.com');
      expect(result.emails[0].to?.[0].name).toBe('Smith, John');
      expect(result.emails[0].to?.[1].email).toBe('jane@example.com');
      expect(result.emails[0].to?.[1].name).toBe('Doe, Jane');
    });

